head.script:
scwin.carryingVesselManagementNumber = "";
scwin.selectTabMenu = 0;


scwin.onpageload = function() {
    // D0604009

    const codeOptions = [
        { grpCd : "OP195", compID : "gr_carryingVesselCommodityEachResultsInfo:impExpClsCd"}
    ];
    $c.data.setCommonCode(codeOptions);

    var params = $c.data.getParameter();

    scwin.carryingVesselManagementNumber = params.carryingVesselManagementNumber == null ? "" : params.carryingVesselManagementNumber;  // 본선관리번호
};

scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        ed_cvsslMgntNo.setValue(scwin.carryingVesselManagementNumber);
        ed_cvsslMgntNo.focus();

        if (ed_cvsslMgntNo.getValue() != "") {
            scwin.f_Retrieve();
        }
        ///임시        
    }, {"delay":50});
};

//-------------------------------------------------------------------------
// 조회
//------------------------------------------------------------------------- 
scwin.f_Retrieve = async function () {	    

    if(scwin.selectTabMenu == 1 && ed_plcvsslMgntNo.getValue() !=""){
    	ed_cvsslMgntNo.setValue(ed_plcvsslMgntNo.getValue());
    }
	// 필수항목 체크 

	if(scwin.selectTabMenu == 0){
        var chk1 = await $c.gus.cfValidate([ed_cvsslMgntNo]);
        if(!chk1) {
            return;
        }
	}

	// 필수항목 체크 
	if(scwin.selectTabMenu == 1){
        var chk2 = await $c.gus.cfValidate([ed_plcvsslMgntNo]);
        if(!chk2) {
            return;
        }
	}

	if(scwin.selectTabMenu == 0){
		ed_plcvsslMgntNo.setValue(ed_cvsslMgntNo.getValue());
	}

	//tr_Retrieve.Post();
    $c.sbm.execute(sbm_Retrieve);
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
	if(scwin.selectTabMenu == 0){
		$c.gus.cfInitObjects(search_cond,null);
	}else{
		$c.gus.cfInitObjects(search_cond1,null);
	}	
}

