scwin.expSD113 = function (prflosItemCd, realAmt, cpRealAmt) {
    return $c.gus.decode(prflosItemCd,"D001", "", "E001","", parseFloat(realAmt-cpRealAmt));
}

scwin.expIncRatio = function (prflosItemCd, realAmt, cpRealAmt) {
    return $c.gus.decode(cpRealAmt,0,0, $c.gus.decode(prflosItemCd,"C001", "", "D001","", "E001", "",  parseFloat((realAmt-cpRealAmt)/cpRealAmt)*100 ));
}


scwin.excelDown1 = function () {
    const options = {
        fileName : "본선품명별실적.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName : "본선품명별실적",
        startRowIndex : 0,
        startColumnIndex : 0,
        textAlign : "right"
    };

    // 타이틀
    const infoArr = [{
                    rowIndex : 0, colIndex : 0, rowSpan : 1, colSpan : 9, textAlign : "right", 
                    drawBorder : false, fontSize : "18px"
                }];


    $c.data.downloadGridViewExcel(gr_carryingVesselCommodityEachResultsInfo, options, infoArr);
}

